import { mkdir, readFile, writeFile } from "node:fs/promises";

const cssPath = new URL("../.generated/styles.css", import.meta.url);
const stylesModulePath = new URL("../src/generated/styles.ts", import.meta.url);
const leafletCssPath = new URL("../node_modules/leaflet/dist/leaflet.css", import.meta.url);
const leafletJsPath = new URL("../node_modules/leaflet/dist/leaflet.js", import.meta.url);
const leafletCssModulePath = new URL("../src/generated/leaflet-css.ts", import.meta.url);
const leafletJsModulePath = new URL("../src/generated/leaflet-js.ts", import.meta.url);

const stylesCss = await readFile(cssPath, "utf8");
const leafletCss = await readFile(leafletCssPath, "utf8");
const leafletJs = (await readFile(leafletJsPath, "utf8")).replace(/\n\/\/# sourceMappingURL=.*$/m, "");
const stylesModuleSource = `// Generated by npm run build:css. Do not edit by hand.\nconst stylesheet = ${JSON.stringify(
  stylesCss,
)};\n\nexport default stylesheet;\n`;
const leafletCssModuleSource = `// Generated by npm run build:css. Do not edit by hand.\nconst stylesheet = ${JSON.stringify(
  leafletCss,
)};\n\nexport default stylesheet;\n`;
const leafletJsModuleSource = `// Generated by npm run build:css. Do not edit by hand.\nconst script = ${JSON.stringify(
  leafletJs,
)};\n\nexport default script;\n`;

await mkdir(new URL("../src/generated/", import.meta.url), { recursive: true });
await writeFile(stylesModulePath, stylesModuleSource, "utf8");
await writeFile(leafletCssModulePath, leafletCssModuleSource, "utf8");
await writeFile(leafletJsModulePath, leafletJsModuleSource, "utf8");
